package com.company.snackledger.server.service;import org.springframework.stereotype.Service;import java.nio.charset.StandardCharsets;import java.security.*;import java.util.HexFormat;@Service public class ApiKeyService{public String hash(String key){try{var md=MessageDigest.getInstance("SHA-256");return HexFormat.of().formatHex(md.digest(key.getBytes(StandardCharsets.UTF_8)));}catch(Exception e){throw new IllegalStateException(e);}} public boolean matches(String key,String hash){return key!=null&&hash(key).equals(hash);}}
